      "title": "Entrance - Private Vehicle",
      "cost": "$35.00",
      "description": "This fee is valid for seven consecutive days for a non-commercial car, pickup truck, RV, or van with 15 or fewer passenger seats. This fee covers the vehicle and everyone inside of it. Per-person nonresident fees still apply."
    },
    {
      "title": "Entrance - Motorcycle",
      "cost": "$30.00",
      "description": "Valid for 7 days. Admits up to 2 private, non-commercial motorcycles with up to 4 total passengers. Per-person nonresident fees still apply."
    },
    {
      "title": "Entrance - Per Person",
      "cost": "$20.00",
      "description": "This fee is valid for seven consecutive days for people entering on foot, a bicycle, a horse, or a non-commercial bus or van. People 15 years and younger are free."
    },
    {
      "title": "Entrance - Non-commercial Groups",
      "cost": "$300.00",
      "description": "The per-person fee is $20 to a maximum of $300 per vehicle. People 15 years and younger are free."
    },
    {
      "title": "Entrance - Education/Academic Groups",
      "cost": "$0.00",
      "description": "An educational fee waiver is available for educational and scientific groups that are accredited or tax-exempt for educational purposes planning a trip for educational or scientific purposes related to Yosemite that is not primarily recreational."
    },
    {
      "title": "Commercial Entrance - Per Person",
      "cost": "$20.00",
      "description": "The fee is $20 per person for any resident 16 years or older. For any nonresident the fee is $100 per person for anyone 16 years or older. This fee is valid for seven consecutive days."
    },
    {
      "title": "Nonresident",
      "cost": "$100.00",
      "description": "Each non-US resident aged 16 and older visiting Yosemite National Park must pay a $100 nonresident fee (in addition to the standard entrance fee), unless admitted with an Annual or America the Beautiful Pass. This includes nonresidents entering as part of a commercial tour group, commercial use authorization (CUA) group, or concessioner tour group."
    },
    {
      "title": "Commercial Entrance - Mini-bus",
      "cost": "$200.00",
      "description": "This fee is valid for seven consecutive days. For any nonresident there is an additional fee of $100 per person for anyone 16 years or older. A commercial use authorization is required."
